UPDATE players SET league='Premier League' WHERE position IN ('LD','LE') AND club IN ('Liverpool','Manchester City','Manchester United','Arsenal','Chelsea','Newcastle United','Tottenham Hotspur','Brighton & Hove Albion','Aston Villa','Brentford','AFC Bournemouth','Everton');
